package org.eclipse.rdf4j.sail.lmdb;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.io.File;
import java.util.List;
import java.util.concurrent.TimeUnit;

import org.eclipse.rdf4j.common.transaction.IsolationLevels;
import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.model.vocabulary.XSD;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.algebra.evaluation.sketch.SketchBasedJoinEstimator;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.eclipse.rdf4j.sail.lmdb.model.LmdbValue;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class LmdbExactJoinSurfaceIdScanTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final IRI KNOWS = VF.createIRI("urn:test:knows");
	private static final IRI NAME = VF.createIRI("urn:test:name");
	private static final IRI VALUE = VF.createIRI("urn:test:value");
	private static final IRI MARKER = VF.createIRI("urn:test:marker");

	@Test
	void exactJoinSurfaceUsesLmdbIdScanAndReportsTelemetry(@TempDir File dataDir) throws Exception {
		LmdbStore store = new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc,psoc"));
		SailRepository repository = new SailRepository(store);
		try {
			repository.init();
			loadResourceJoinData(repository);
			SketchBasedJoinEstimator estimator = rebuildAndGetEstimator(store);

			StatementPattern knows = pattern("person", KNOWS, "friend");
			StatementPattern name = pattern("friend", NAME, "name");

			double rows = estimator.estimateExactJoinSurfaceRows(List.of(knows, name), "friend");

			assertEquals(4.0d, rows, 0.01d, "Expected ID scan to count the shared ?friend surface exactly");
			assertLmdbIdTelemetry(knows, name);
		} finally {
			repository.shutDown();
			LmdbTestUtil.deleteDir(dataDir);
		}
	}

	@Test
	void missingBoundConstantIdReturnsZeroWithoutCreatingValue(@TempDir File dataDir) throws Exception {
		LmdbStore store = new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc,psoc"));
		SailRepository repository = new SailRepository(store);
		try {
			repository.init();
			loadResourceJoinData(repository);
			SketchBasedJoinEstimator estimator = rebuildAndGetEstimator(store);
			ValueStore valueStore = (ValueStore) store.getBackingStore().getValueFactory();
			IRI missingObject = VF.createIRI("urn:test:missing-object");
			assertEquals(LmdbValue.UNKNOWN_ID, valueStore.getId(missingObject),
					"Precondition: missing test value must not already exist");

			StatementPattern knows = pattern("person", KNOWS, "friend");
			StatementPattern impossibleName = new StatementPattern(
					Var.of("friend"),
					Var.of("namePredicate", NAME),
					Var.of("missing", missingObject));

			double rows = estimator.estimateExactJoinSurfaceRows(List.of(knows, impossibleName), "friend");

			assertEquals(0.0d, rows, 0.0d, "A missing bound constant ID should make the surface exactly empty");
			assertEquals(LmdbValue.UNKNOWN_ID, valueStore.getId(missingObject),
					"The read-only ID lookup must not create a value-store entry");
			assertLmdbIdTelemetry(knows, impossibleName);
		} finally {
			repository.shutDown();
			LmdbTestUtil.deleteDir(dataDir);
		}
	}

	@Test
	void inlinedLiteralSharedValuesStayOnIdPath(@TempDir File dataDir) throws Exception {
		LmdbStore store = new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc,psoc"));
		SailRepository repository = new SailRepository(store);
		try {
			repository.init();
			loadLiteralJoinData(repository);
			SketchBasedJoinEstimator estimator = rebuildAndGetEstimator(store);

			StatementPattern observations = pattern("observation", VALUE, "value");
			StatementPattern markers = pattern("marker", MARKER, "value");

			double rows = estimator.estimateExactJoinSurfaceRows(List.of(observations, markers), "value");

			assertEquals(3.0d, rows, 0.01d, "Expected inlined integer literal IDs to join without value resolution");
			assertLmdbIdTelemetry(observations, markers);
		} finally {
			repository.shutDown();
			LmdbTestUtil.deleteDir(dataDir);
		}
	}

	private static SketchBasedJoinEstimator rebuildAndGetEstimator(LmdbStore store) throws InterruptedException {
		SketchBasedJoinEstimator estimator = store.getBackingStore().getSketchBasedJoinEstimator();
		estimator.rebuild();
		assertTrue(store.awaitSketchesReady(30, TimeUnit.SECONDS), "Expected sketches to be ready after rebuild");
		return estimator;
	}

	private static StatementPattern pattern(String subjectVar, IRI predicate, String objectVar) {
		return new StatementPattern(
				Var.of(subjectVar),
				Var.of("predicate", predicate),
				Var.of(objectVar));
	}

	private static void loadResourceJoinData(SailRepository repository) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.NONE);
			IRI friend0 = VF.createIRI("urn:test:friend:0");
			IRI friend1 = VF.createIRI("urn:test:friend:1");
			IRI friend2 = VF.createIRI("urn:test:friend:2");
			connection.add(VF.createIRI("urn:test:person:0"), KNOWS, friend0);
			connection.add(VF.createIRI("urn:test:person:1"), KNOWS, friend0);
			connection.add(VF.createIRI("urn:test:person:2"), KNOWS, friend1);
			connection.add(VF.createIRI("urn:test:person:3"), KNOWS, friend2);
			connection.add(friend0, NAME, VF.createLiteral("Alice"));
			connection.add(friend1, NAME, VF.createLiteral("Bob"));
			connection.add(friend1, NAME, VF.createLiteral("Robert"));
			connection.commit();
		}
	}

	private static void loadLiteralJoinData(SailRepository repository) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.NONE);
			connection.add(VF.createIRI("urn:test:observation:0"), VALUE, VF.createLiteral("50", XSD.INT));
			connection.add(VF.createIRI("urn:test:observation:1"), VALUE, VF.createLiteral("50", XSD.INT));
			connection.add(VF.createIRI("urn:test:observation:2"), VALUE, VF.createLiteral("60", XSD.INT));
			connection.add(VF.createIRI("urn:test:observation:3"), VALUE, VF.createLiteral("80", XSD.INT));
			connection.add(VF.createIRI("urn:test:marker:0"), MARKER, VF.createLiteral("50", XSD.INT));
			connection.add(VF.createIRI("urn:test:marker:1"), MARKER, VF.createLiteral("60", XSD.INT));
			connection.add(VF.createIRI("urn:test:marker:2"), MARKER, VF.createLiteral("70", XSD.INT));
			connection.commit();
		}
	}

	private static void assertLmdbIdTelemetry(TupleExpr first, TupleExpr second) {
		String firstSource = first.getStringMetricPlanned("optimizer.exactJoinSurfaceSource");
		String secondSource = second.getStringMetricPlanned("optimizer.exactJoinSurfaceSource");
		assertTrue("lmdb-id".equals(firstSource) || "lmdb-id".equals(secondSource),
				() -> "Expected LMDB ID exact-surface telemetry. first=" + firstSource + ", second="
						+ secondSource);
	}
}
